  '.ns-progress {\r\n  width: 100%;\r\n}\r\n\r\n.ns-progress__track {\r\n  position: relative;\r\n  display: block;\r\n  width: 100%;\r\n  overflow: hidden;\r\n  border-radius: var(--ns-radius-full);\r\n  background: color-mix(in srgb, var(--ns-border-hover) 90%, transparent);\r\n}\r\n\r\n.ns-progress--sm .ns-progress__track {\r\n  height: 0.325rem;\r\n}\r\n\r\n.ns-progress--md .ns-progress__track {\r\n  height: 0.5rem;\r\n}\r\n\r\n.ns-progress--lg .ns-progress__track {\r\n  height: 0.7rem;\r\n}\r\n\r\n.ns-progress__bar {\r\n  display: block;\r\n  height: 100%;\r\n  border-radius: inherit;\r\n  background: var(--ns-primary);\r\n  transition: width var(--ns-ease-normal);\r\n}\r\n\r\n.ns-progress--secondary .ns-progress__bar {\r\n  background: var(--ns-secondary);\r\n}\r\n\r\n.ns-progress--success .ns-progress__bar {\r\n  background: var(--ns-success);\r\n}\r\n\r\n.ns-progress--warning .ns-progress__bar {\r\n  background: var(--ns-warning);\r\n}\r\n\r\n.ns-progress--destructive .ns-progress__bar {\r\n  background: var(--ns-destructive);\r\n}\r\n\r\n.ns-progress--indeterminate .ns-progress__bar {\r\n  width: 42%;\r\n  animation: ns-progress-indeterminate 1.2s ease-in-out infinite;\r\n}\r\n\r\n@keyframes ns-progress-indeterminate {\r\n  0% {\r\n    transform: translateX(-120%);\r\n  }\r\n\r\n  50% {\r\n    transform: translateX(30%);\r\n  }\r\n\r\n  100% {\r\n    transform: translateX(180%);\r\n  }\r\n}\r\n\r\n/* Reduced motion: indeterminate sweep becomes a static partial fill. */\r\n@media (prefers-reduced-motion: reduce) {\r\n  .ns-progress--indeterminate .ns-progress__bar {\r\n    animation: none;\r\n    width: 42%;\r\n    transform: translateX(70%);\r\n  }\r\n}\r\n';
const template_043 =
  "/**\n * @component Progress\n * @layer 2\n * @depends theme-seed\n * @description Determinate or indeterminate progress indicator for jobs, uploads, and deferred flows.\n */\n\nimport type { JSX, VNode } from 'preact';\nimport { cn } from '../../lib/cn.ts';\n\nexport type ProgressVariant = 'primary' | 'secondary' | 'success' | 'warning' | 'destructive';\nexport type ProgressSize = 'sm' | 'md' | 'lg';\n\nexport interface ProgressProps\n  extends Omit<JSX.HTMLAttributes<HTMLDivElement>, 'class' | 'children'> {\n  class?: string;\n  indeterminate?: boolean;\n  label?: string;\n  max?: number;\n  size?: ProgressSize;\n  value?: number;\n  variant?: ProgressVariant;\n}\n\nconst SIZE_CLASSES: Record<ProgressSize, string> = {\n  sm: 'ns-progress--sm',\n  md: 'ns-progress--md',\n  lg: 'ns-progress--lg',\n};\n\nconst VARIANT_CLASSES: Record<ProgressVariant, string | undefined> = {\n  primary: undefined,\n  secondary: 'ns-progress--secondary',\n  success: 'ns-progress--success',\n  warning: 'ns-progress--warning',\n  destructive: 'ns-progress--destructive',\n};\n\nfunction clamp(value: number, min: number, max: number): number {\n  return Math.min(Math.max(value, min), max);\n}\n\nexport function Progress({\n  class: className,\n  indeterminate = false,\n  label = 'Progress',\n  max = 100,\n  size = 'md',\n  value = 0,\n  variant = 'primary',\n  ...props\n}: ProgressProps): VNode {\n  const safeMax = max > 0 ? max : 100;\n  const normalizedValue = clamp(value, 0, safeMax);\n  const width = `${(normalizedValue / safeMax) * 100}%`;\n\n  return (\n    <div\n      {...props}\n      role='progressbar'\n      aria-label={label}\n      aria-valuemin={0}\n      aria-valuemax={safeMax}\n      aria-valuenow={indeterminate ? undefined : normalizedValue}\n      class={cn(\n        'ns-progress',\n        SIZE_CLASSES[size],\n        VARIANT_CLASSES[variant],\n        indeterminate && 'ns-progress--indeterminate',\n        className,\n      )}\n    >\n      <span class='ns-progress__track'>\n        <span class='ns-progress__bar' style={indeterminate ? undefined : { width }} />\n      </span>\n    </div>\n  );\n}\n";
